```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TeamVestingVault {
    address private _owner;

    mapping(address => uint256) private _allocation;
    mapping(address => uint256) private _releaseTime;
    mapping(address => uint256) private _withdrawn;

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockTime);
    event Withdrawal(address indexed investor, uint256 amount);

    constructor() {
        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    // Getters for public mappings
    function allocation(address investor) public view returns (uint256) {
        return _allocation[investor];
    }

    function releaseTime(address investor) public view returns (uint256) {
        return _releaseTime[investor];
    }

    function withdrawn(address investor) public view returns (uint256) {
        return _withdrawn[investor];
    }

    function addInvestor(address investor, uint256 amount, uint256 unlockTime) external onlyOwner {
        require(investor != address(0), "Invalid investor address");
        require(amount > 0, "Amount must be greater than zero");

        _allocation[investor] = amount;
        _releaseTime[investor] = unlockTime;

        emit InvestorAdded(investor, amount, unlockTime);
    }

    function withdraw() external {
        uint256 amount = _allocation[msg.sender];
        uint256 time = _releaseTime[msg.sender];

        require(amount > 0, "No allocation available");
        require(block.timestamp >= time, "Withdrawal not yet available");

        // Transfer funds before setting allocation to 0
        payable(msg.sender).transfer(amount);

        // Set allocation to 0 after transferring funds
        _allocation[msg.sender] = 0;
        _withdrawn[msg.sender] += amount;

        emit Withdrawal(msg.sender, amount);
    }
}
